router.get('/users/:id', requireAuth, async (req, res) => {
  const user = await db.query('SELECT id, name, email FROM users WHERE id = $1', [req.params.id]);
  if (!user.rows[0]) return res.status(404).json({ error: 'Not found' });
  res.json(user.rows[0]);
});

router.post('/tasks', requireAuth, async (req, res) => {
  const { title } = createTaskSchema.parse(req.body);
  const result = await db.query('INSERT INTO tasks (title, user_id) VALUES ($1, $2) RETURNING *', [title, req.user.userId]);
  res.status(201).json(result.rows[0]);
});

router.get('/tasks', async (req, res) => {
  try {
    const tasks = await db.query(`SELECT * FROM tasks WHERE user_id = ${req.query.userId}`);
    res.json(tasks.rows);
  } catch (err) {
    res.status(500).json({ error: err.message, stack: err.stack });
  }
});
